import jwt
import datetime
from typing import Dict, Any, Optional

SECRET_KEY = "your-secret-key-change-this-in-production"
ALGORITHM = "HS256"
TOKEN_EXPIRATION_HOURS = 24


def generate_jwt_token(user_id: int, role: str, expires_in_hours: int = TOKEN_EXPIRATION_HOURS) -> str:
    """
    Generate a JWT token for user authentication.
    
    Args:
        user_id: The unique identifier for the user
        role: The user's role (e.g., 'admin', 'user', 'guest')
        expires_in_hours: Token expiration time in hours (default: 24)
    
    Returns:
        JWT token as a string
    """
    expiration = datetime.datetime.utcnow() + datetime.timedelta(hours=expires_in_hours)
    
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': expiration,
        'iat': datetime.datetime.utcnow()
    }
    
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def verify_jwt_token(token: str) -> Optional[Dict[str, Any]]:
    """
    Verify and decode a JWT token.
    
    Args:
        token: The JWT token to verify
    
    Returns:
        Decoded payload if valid, None if invalid or expired
    """
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def refresh_token(token: str, expires_in_hours: int = TOKEN_EXPIRATION_HOURS) -> Optional[str]:
    """
    Refresh an existing token with a new expiration time.
    
    Args:
        token: The existing JWT token
        expires_in_hours: New expiration time in hours
    
    Returns:
        New JWT token if the old token is valid, None otherwise
    """
    payload = verify_jwt_token(token)
    if payload:
        return generate_jwt_token(
            user_id=payload['user_id'],
            role=payload['role'],
            expires_in_hours=expires_in_hours
        )
    return None


def get_user_from_token(token: str) -> Optional[Dict[str, Any]]:
    """
    Extract user information from a JWT token.
    
    Args:
        token: The JWT token
    
    Returns:
        Dictionary with user_id and role if valid, None otherwise
    """
    payload = verify_jwt_token(token)
    if payload:
        return {
            'user_id': payload['user_id'],
            'role': payload['role']
        }
    return None


